Calculate_Effort_for_External_Service_Ch.inputs:
@if(
	greaterOrEquals(
		add(
			variables('varChildTasksProcessed'), 
			1
		),
		outputs('Number_of_required_Child_Tasks_[External_Service]')
	),
	if(
		greaterOrEquals(
			float(
				formatNumber(
					sub(
						items('Apply_to_each_aggregated_External_Service_by_Project_Category')?['AggregatedQuantity'],
						mul(
							variables('varMaxProjectTaskEffort'),
							variables('varChildTasksProcessed')
						)
					),
					'0.00'
				)
			),
			sub(
				items('Apply_to_each_aggregated_External_Service_by_Project_Category')?['AggregatedQuantity'],
				mul(
					variables('varMaxProjectTaskEffort'),
					variables('varChildTasksProcessed')
				)
			)
		),
		float(
			formatNumber(
				sub(
					items('Apply_to_each_aggregated_External_Service_by_Project_Category')?['AggregatedQuantity'],
					mul(
						variables('varMaxProjectTaskEffort'),
						variables('varChildTasksProcessed')
					)
				),
				'0.00'
			)
		),
		float(
			formatNumber(
				add(
					sub(
						items('Apply_to_each_aggregated_External_Service_by_Project_Category')?['AggregatedQuantity'],
						mul(
							variables('varMaxProjectTaskEffort'),
							variables('varChildTasksProcessed')
						)
					),
					0.01
				),
				'0.00'
			)
		)
	),
	variables('varMaxProjectTaskEffort')
)

